# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

import argparse
from kafka.admin import KafkaAdminClient, NewTopic

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--topic', type=str, required=True, help='Name of the topic to create or manage')
    parser.add_argument('--partitions', type=int, default=1, help='Number of partitions for the topic')
    parser.add_argument('--replication-factor', type=int, default=1, help='Replication factor for the topic')
    parser.add_argument('--admin-config', action='append', nargs=2, metavar=('key', 'value'), help='Topic configuration key-value pairs')

    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers='localhost:9092')

    topic_config = {key: value for key, value in args.admin_config} if args.admin_config else None

    new_topic = NewTopic(
        name=args.topic,
        num_partitions=args.partitions,
        replication_factor=args.replication_factor,
        topic_configs=topic_config
    )

    topics_to_create = admin_client.create_topics([new_topic])

    for topic, future in topics_to_create.items():
        try:
            future.result()
            print(f"Topic {topic} created successfully")
        except Exception as e:
            print(f"Failed to create topic {topic}: {e}")

if __name__ == "__main__":
    main()